Polling function: GitHub Issue Comment Watcher
------------------------------------------------
Polling cursor contract:
  - Input:  {"since": "2025-01-01T00:00:00Z" or ""}
  - Output: {
      "comments": [...],
      "since": "2025-03-21T12:34:56Z"   # latest created_at from this batch
    }

The Forge runtime will pass the output.since back as input.since
on the next poll cycle, forming a continuous cursor chain.
"""
import json
import os
from datetime import datetime, timezone
from typing import Optional

# ── configurable via function call args ──
DEFAULT_REPO = os.getenv("GH_REPO", "octocat/Hello-World")
DEFAULT_ISSUE = int(os.getenv("GH_ISSUE_NUMBER", "1"))
DEFAULT_TOKEN = os.getenv("GH_TOKEN", "")


def run(
    repo: str = DEFAULT_REPO,
    issue_number: int = DEFAULT_ISSUE,
    token: str = DEFAULT_TOKEN,
    since: str = "",
) -> dict:
    """
    Fetch issue comments newer than `since`.
    Returns dict with "comments" (list) and "since" (latest created_at ISO string).
    """
    import urllib.request
    import base64

    if not token:
        # Fallback: unauthenticated (rate-limited to 60/hr)
        headers = {
            "Accept": "application/vnd.github.v3+json",
            "User-Agent": "Forgify-Poller/1.0",
        }
    else:
        headers = {
            "Accept": "application/vnd.github.v3+json",
            "User-Agent": "Forgify-Poller/1.0",
            "Authorization": f"Bearer {token}",
        }

    url = f"https://api.github.com/repos/{repo}/issues/{issue_number}/comments"
    if since:
        # GitHub API expects ISO 8601, URL-encoded
        from urllib.parse import urlencode
        url += "?" + urlencode({"since": since})

    req = urllib.request.Request(url, headers=headers)
    try:
        with urllib.request.urlopen(req, timeout=30) as resp:
            raw = resp.read().decode()
            comments = json.loads(raw)
    except urllib.error.HTTPError as e:
        # On error, return empty list so we don't lose cursor
        return {"comments": [], "since": since, "error": str(e)}
    except Exception as e:
        return {"comments": [], "since": since, "error": str(e)}

    # ── extract new comments that are strictly after `since` ──
    new_comments = []
    latest_since = since  # keep old cursor if no new comments

    for c in comments:
        created_at = c.get("created_at", "")
        if not created_at:
            continue

        # GitHub returns comments sorted ascending by created_at
        # If `since` is set, the API already filters; but we double-check
        if since and created_at <= since:
            continue

        new_comments.append({
            "id": c["id"],
            "user": c["user"]["login"],
            "body": c["body"],
            "created_at": created_at,
            "html_url": c["html_url"],
        })

        # Update cursor to the latest seen timestamp
        if created_at > latest_since:
            latest_since = created_at

    return {
        "comments": new_comments,
        "since": latest_since,
    }
"}
